from solution import count_calls


def test_starts_at_zero():
    @count_calls
    def f():
        return None

    assert f.calls == 0, "decorated function must expose .calls == 0 before any call"


def test_counts_each_call():
    @count_calls
    def add(a, b):
        return a + b

    add(1, 2)
    add(3, 4)
    add(5, 6)
    assert add.calls == 3, "expected .calls to equal the number of invocations"


def test_returns_underlying_value_and_forwards_args():
    @count_calls
    def greet(name, *, loud=False):
        return name.upper() if loud else name

    assert greet("ada") == "ada"
    assert greet("ada", loud=True) == "ADA"
    assert greet.calls == 2


def test_preserves_metadata():
    @count_calls
    def documented():
        """A documented function."""
        return 1

    assert documented.__name__ == "documented", "use functools.wraps to keep __name__"
    assert documented.__doc__ == "A documented function."


def test_two_decorated_functions_count_independently():
    @count_calls
    def a():
        return 1

    @count_calls
    def b():
        return 2

    a()
    a()
    b()
    assert a.calls == 2 and b.calls == 1, "each decorated function needs its own counter"

