import time

from solution import timed


def test_duration_none_before_call():
    @timed
    def f():
        return 1

    assert f.last_duration is None, "last_duration must be None until the first call"


def test_returns_value_unchanged():
    @timed
    def add(a, b):
        return a + b

    assert add(2, 3) == 5


def test_records_a_nonnegative_duration(monkeypatch):
    # Drive a fake monotonic clock so the test is deterministic (no real sleep).
    ticks = iter([10.0, 10.5])
    monkeypatch.setattr(time, "perf_counter", lambda: next(ticks))

    @timed
    def work():
        return "done"

    assert work() == "done"
    assert abs(work_duration := work.last_duration) >= 0.0
    assert abs(work_duration - 0.5) < 1e-9, "duration must be end-minus-start of perf_counter"


def test_duration_updates_on_each_call(monkeypatch):
    ticks = iter([0.0, 1.0, 100.0, 102.0])
    monkeypatch.setattr(time, "perf_counter", lambda: next(ticks))

    @timed
    def work():
        return None

    work()
    assert abs(work.last_duration - 1.0) < 1e-9
    work()
    assert abs(work.last_duration - 2.0) < 1e-9, "last_duration must reflect the most recent call"


def test_preserves_metadata():
    @timed
    def documented():
        """Docs here."""
        return 1

    assert documented.__name__ == "documented"
    assert documented.__doc__ == "Docs here."


def test_records_duration_even_if_function_raises(monkeypatch):
    ticks = iter([0.0, 3.0])
    monkeypatch.setattr(time, "perf_counter", lambda: next(ticks))

    @timed
    def boom():
        raise ValueError("nope")

    # A timing decorator that only records on success is a classic bug.
    try:
        boom()
    except ValueError:
        pass
    assert boom.last_duration is not None, "even a raising call should still be timed"

