import pytest

from solution import retry


def test_returns_immediately_on_success():
    calls = []

    @retry
    def ok():
        calls.append(1)
        return "value"

    assert ok() == "value"
    assert len(calls) == 1, "a function that succeeds must not be retried"


def test_succeeds_after_transient_failures():
    state = {"n": 0}

    @retry
    def flaky():
        state["n"] += 1
        if state["n"] < 3:
            raise ConnectionError("transient")
        return "recovered"

    assert flaky() == "recovered"
    assert state["n"] == 3, "should keep trying until the call succeeds (within 3 attempts)"


def test_gives_up_after_three_attempts_and_reraises():
    state = {"n": 0}

    @retry
    def always_fails():
        state["n"] += 1
        raise ValueError("boom")

    with pytest.raises(ValueError, match="boom"):
        always_fails()
    assert state["n"] == 3, "must attempt exactly 3 times before giving up"


def test_forwards_arguments():
    @retry
    def add(a, b, *, c=0):
        return a + b + c

    assert add(1, 2, c=3) == 6


def test_preserves_metadata():
    @retry
    def documented():
        """A documented function."""
        return 1

    assert documented.__name__ == "documented"
    assert documented.__doc__ == "A documented function."


def test_reraises_the_last_exception_instance():
    # Tricky: each attempt raises a distinct exception; the one propagated
    # must be from the final attempt, not the first.
    raised = []

    @retry
    def fails_differently():
        exc = RuntimeError(f"attempt-{len(raised)}")
        raised.append(exc)
        raise exc

    with pytest.raises(RuntimeError) as info:
        fails_differently()
    assert str(info.value) == "attempt-2", "must re-raise the exception from the last attempt"
    assert info.value is raised[-1]

