import functools


def retry(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        attempts = 3
        last_exc = None
        for _ in range(attempts):
            try:
                return func(*args, **kwargs)
            except Exception as exc:  # noqa: BLE001 - retry intentionally catches broadly
                last_exc = exc
        # All attempts failed: re-raise the most recent exception.
        raise last_exc

    return wrapper
